const express = require('express');
const app = express();
app.use(express.json());

let rewards = {
  "level1": 100,
  "level2": 200,
  "level3": 300,
  // Add more levels as needed
};

app.post('/completeLevel', (req, res) => {
  let level = req.body.level;
  let score = req.body.score;
  let time = req.body.time;

  // Implement your own logic to calculate rewards based on score and time
  let reward = calculateReward(score, time);

  res.json({
    message: `Level ${level} completed`,
    reward: reward
  });
});

app.get('/claimReward', (req, res) => {
  let level = req.query.level;

  if (rewards[level]) {
    res.json({
      message: `Reward for level ${level} claimed`,
      reward: rewards[level]
    });
  } else {
    res.status(404).json({
      message: `No reward found for level ${level}`
    });
  }
});

function calculateReward(score, time) {
  // Implement your own logic to calculate rewards based on score and time
  return score / time;
}

const port = process.env.PORT || 3000;
app.listen(port, () => console.log(`Server running on port ${port}`));